SELECT t1.id, t1.order_sn, t1.total_amount, t1.payment_amount, t1.payment_channel, t1.payment_method, t1.status, t1.total_amount, t1.total_quantity, t1.create_time, t1.member_id, t1.source, t1.remark FROM oms_order t1
AND ( t1.order_sn like concat('%',#{queryParams.keyword},'%') OR CAST(t1.id AS CHAR) LIKE CONCAT('%', #{queryParams.keyword}, '%') )
AND t1.status= #{queryParams.status}
AND t1.create_time >= #{queryParams.startDate}
AND t1.create_time < DATE_ADD(#{queryParams.endDate}, INTERVAL 1 DAY)
AND t1.payment_method = #{queryParams.payType}
AND t1.source = #{queryParams.orderType}
AND t1.total_amount >= #{queryParams.minAmount}
AND t1.total_amount <= #{queryParams.maxAmount}
AND t1.source = #{queryParams.source}
ORDER BY t1.create_time DESC

SELECT COUNT(*) FROM oms_order
deleted = 0
AND status = #{queryParams.status}
AND create_time >= #{queryParams.startDate}
AND create_time < DATE_ADD(#{queryParams.endDate}, INTERVAL 1 DAY)
AND ( order_sn LIKE CONCAT('%', #{queryParams.keyword}, '%') OR CAST(id AS CHAR) LIKE CONCAT('%', #{queryParams.keyword}, '%') OR user_phone LIKE CONCAT('%', #{queryParams.keyword}, '%') )
